#include<bits/stdc++.h>
using namespace std;
struct student{
	char name[35];
	int total;
} a[110];
bool cmp(student a,student b)
{
	if(a.total!=b.total)
	return a.total>b.total;
	else 
	if(strcmp(a.name,b.name)<0)
	return 1;
	else
	return 0;
}

int n;
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%s",a[i].name);
		scanf("%d",&(a[i].total));
	}
sort(a+1,a+n+1,cmp);
	for(int i=1;i<=n;i++)
	{
		printf("%s %d\n",a[i].name,a[i].total);
	}
	return 0;
}
